import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.security.saml2.provider.service.authentication.Saml2AuthenticationToken;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RestController;

import javax.servlet.http.HttpSession;
import java.util.Map;

@SpringBootApplication
public class SamlServiceProviderApplication {

    public static void main(String[] args) {
        SpringApplication.run(SamlServiceProviderApplication.class, args);
    }

    @RestController
    public class SamlController {

        @GetMapping("/saml/login")
        public String samlLogin(Saml2AuthenticationToken authentication, HttpSession session) {
            // Extract user attributes from the SAML assertion
            Map<String, Object> claims = (Map<String, Object>) authentication.getPrincipal().getAttributes();
            String username = (String) claims.get("username");
            String email = (String) claims.get("email");

            // Store user attributes in the session
            session.setAttribute("username", username);
            session.setAttribute("email", email);

            return "User authenticated: " + username;
        }
    }
}